from flask import Flask, jsonify, request
from datetime import datetime

app = Flask(__name__)

todos = {}
next_id = 1


def todo_not_found(todo_id):
    return jsonify({"error": f"Todo {todo_id} not found"}), 404


@app.route("/todos", methods=["GET"])
def list_todos():
    return jsonify(list(todos.values())), 200


@app.route("/todos", methods=["POST"])
def create_todo():
    global next_id
    data = request.get_json(silent=True) or {}

    if not data.get("title"):
        return jsonify({"error": "title is required"}), 400

    todo = {
        "id": next_id,
        "title": data["title"],
        "description": data.get("description"),
        "due_date": data.get("due_date"),
        "completed": False,
        "created_at": datetime.utcnow().isoformat(),
    }
    todos[next_id] = todo
    next_id += 1
    return jsonify(todo), 201


@app.route("/todos/<int:todo_id>", methods=["GET"])
def get_todo(todo_id):
    todo = todos.get(todo_id)
    if todo is None:
        return todo_not_found(todo_id)
    return jsonify(todo), 200


@app.route("/todos/<int:todo_id>", methods=["PUT"])
def update_todo(todo_id):
    todo = todos.get(todo_id)
    if todo is None:
        return todo_not_found(todo_id)

    data = request.get_json(silent=True) or {}
    for field in ("title", "description", "due_date", "completed"):
        if field in data:
            todo[field] = data[field]

    if not todo.get("title"):
        return jsonify({"error": "title cannot be empty"}), 400

    return jsonify(todo), 200


@app.route("/todos/<int:todo_id>", methods=["DELETE"])
def delete_todo(todo_id):
    if todo_id not in todos:
        return todo_not_found(todo_id)
    del todos[todo_id]
    return "", 204


if __name__ == "__main__":
    app.run(debug=True)
